// 创建空白检测数据（质检员录入阶段）
export function createEmptyEntryData() {
    return {
        meters: null,
        weight: null,
        joints: null,
        // 针孔检测
        pinholeA: null, pinholeB: null,
        pinholeC: null, pinholeD: null,
        pinholeE: null,
        offlinePinhole: null,
        longitudinalDensity: null,
        densePinhole: false,
        densePinholeNote: '',
        // 表面检测
        surfaceInfo: '',
        slittingQuality: '',
        // 板型检测
        flatnessData: '',
        flatness: null,
        // 其他
        faceDensity: [null, null, null, null, null, null], // 上左/上右/中左/中右/下左/下右
        dyneValue: '',              // 字符串，支持 '30/30缩' 格式
        tubeCore: '',
        frameNo: '',
        // 质量初判
        qualityJudgment: 'nonconform', // 'conform' | 'nonconform'
        defectReasons: [],
        // 操作员信息
        operator: '',               // 主操手
        inspector: '',              // 质检员
        shift: '',                  // 班组：甲/乙/丙
        entryDate: null,            // 录入日期
    }
}

// 创建空白评审数据（质量工程师评审阶段）
export function createEmptyReviewData() {
    return {
        finalJudgment: 'nonconform',  // 'conform' | 'nonconform'
        productGrade: 'A',            // 'A'（一级品）| 'B'（二级品）
        mainConclusion: '',
        deliveryTarget: '',
        downgradeReason: '',
        instructions: [],             // { defectType, locationSide, startMm, endMm, lengthStartM, lengthEndM, treatment }
        note: '',
    }
}

